mapper.sql:
/* wms-outbound-obsubicexpt-sql-oracle.xml - subicExptSql - 부자재 반출 - 부자재 반출 재고 정보 조회 SQL */ SELECT 0 AS CHK /*체크박스*/ , IVLC.CTKEY /*센터 코드*/ , IVLC.OWKEY /*화주 코드*/ , CT.CTNM /*센터명*/ , IVLC.ICKEY /*상품코드*/ , ICB.BARCODE /*바코드*/ , IC.ICNM /*상품명*/ , CTG.CTGNM /*상품대/중/소명*/ , IVLC.IVATKEY /*재고 속성 코드*/ , IVLC.IVSTATUSCD /*재고상태코드*/ , IVLC.LCKEY /*로케이션 코드*/ , IVLC.IVSERIALNO /*재고시리얼번호*/ , IVLC.AVQTY /*가용 수량*/ , 0 AS PISPQTY /*실사수량*/ , IVLC.INSERTDATE /*입력 일시*/ , IVLC.INSERTURKEY /*입력 사용자 ID*/ , IVLC.UPDATEDATE /*수정 일시*/ , IVLC.UPDATEURKEY /*수정 사용자 ID*/ , CASE WHEN BX.BOXBARCODE IS NOT NULL THEN 'Y' ELSE 'N' END AS BOXYN /*박스여부*/ FROM TWORK_INFO_IVATXLC IVLC /*재고 속성별 로케이션별 재고 정보*/ INNER JOIN TWORK_INFO_IVAT IV /*재고속성정보*/ ON IVLC.CTKEY = IV.CTKEY AND IVLC.OWKEY = IV.OWKEY AND IVLC.IVATKEY = IV.IVATKEY INNER JOIN TWORK_MST_LC LC /*로케이션 마스터*/ ON IVLC.CTKEY = LC.CTKEY AND IVLC.LCKEY = LC.LCKEY INNER JOIN TWORK_MST_ZN ZN /*존 마스터*/ ON LC.CTKEY = ZN.CTKEY AND LC.ZNKEY = ZN.ZNKEY INNER JOIN TWORK_MST_IC IC /*상품 마스터*/ ON IV.CTKEY = IC.CTKEY AND IV.OWKEY = IC.OWKEY AND IV.ICKEY = IC.ICKEY INNER JOIN TWORK_MST_CTG CTG /*상품 분류 마스터*/ ON IC.CTKEY = CTG.CTKEY AND IC.OWKEY = CTG.OWKEY AND IC.CTGKEY = CTG.CTGKEY INNER JOIN TWORK_MST_CT CT /*센터 마스터*/ ON IC.CTKEY = CT.CTKEY LEFT JOIN TWORK_MST_ICBARCODE ICB /*상품바코드 마스터*/ ON IC.CTKEY = ICB.CTKEY AND IC.OWKEY = ICB.OWKEY AND IC.ICKEY = ICB.ICKEY AND IC.UOM = ICB.UOM LEFT JOIN TWORK_MST_BOX BX /*박스 마스터*/ ON IC.CTKEY = BX.CTKEY AND IC.ICKEY = BX.ICKEY
#{SEARCH_CONDITION}
AND IVLC.AVQTY > 0 AND ZN.ZNTYPECD = '10' /*10: 보관존*/ AND ZN.ZNKEY = 'SM' /*SM: 부자재 보관존*/
ORDER BY IVLC.ICKEY, IVLC.IVATKEY

