mapper.insert:
/* wms-outbound-obsubicexpt-sql-oracle.xml - subicExptTaHdInsert - 부자재반출 - 작업지시 헤더 등록 */
INSERT INTO TWORK_INFO_TA_HD (
       CTKEY        /*센터코드*/
     , OWKEY        /*화주코드*/
     , TAHDKEY      /*TASK번호*/
     , TATYPECD     /*TASK유형번호*/
     , REGDATE      /*등록일시*/
     , FRWKDATE     /*작업기간_FROM*/
     , TOWKDATE     /*작업기간_TO*/
     , TADDLNDATE   /*TASK마감일시*/
     , TAWKSTATUSCD /*TASK작업상태코드*/
     , INSERTDATE   /*입력일시*/
     , INSERTURKEY  /*입력사용자ID*/
     , UPDATEDATE   /*수정일시*/
     , UPDATEURKEY  /*수정사용자ID*/
) VALUES (
       #{ctkey}
     , #{owkey}
     , #{tahdkey}
     , #{tatypecd}
     , #{sysdate}
     , #{sysdate}
     , #{sysdate}
     , #{sysdate}
     , #{tawkstatuscd}
     , #{sysdate}
     , #{surkey}
     , #{sysdate}
     , #{surkey}
)

mapper.update:
/* wms-outbound-obsubicexpt-sql-oracle.xml - subicExptIvatByLcUpdate - 부자재반출 - 재고 속성별 로케이션별 재고정보 업데이트 */
UPDATE TWORK_INFO_IVATXLC /*재고 속성별 로케이션별 재고 정보*/
   SET AVQTY = AVQTY - #{outqty}
     , TOTQTY = TOTQTY - #{outqty}
     , UPDATEDATE = #{sysdate}
     , UPDATEURKEY = #{surkey}
 WHERE CTKEY = #{ctkey}
   AND OWKEY = #{owkey}
   AND IVATKEY = #{ivatkey}
   AND LCKEY = #{lckey}
   AND ICKEY = #{ickey}
   AND IVSERIALNO = #{ivserialno}
